def minCostClimbingStairs(cost):
    # DP: f[i] = min cost to reach step i, f[i] = cost[i] + min(f[i-1], f[i-2])
    if len(cost) <= 1:
        return 0
    a, b = 0, 0  # f[0], f[1] (cost to stand before step 0/1)
    for i in range(2, len(cost) + 1):
        current = cost[i-1] + min(a, b)
        a, b = b, current
    return min(a, b)

# Test
print(minCostClimbingStairs([1,100,1,1,1,100,1,1,100,1]))  # Output: 6

